sql:
SELECT DISTINCT c.official_name, c.numeric_code
FROM countries c
JOIN access_logs al ON c.country_id = al.country_id;

SELECT data_sources.source_name, data_sources.url, country_sources.*
FROM data_sources
JOIN country_sources ON data_sources.source_id = country_sources.source_id;

SELECT MAX(version_date) 
FROM country_versions 
WHERE country_id = (SELECT country_id FROM countries WHERE official_name = 'Your_Country_Name');

SELECT 
    (SELECT COUNT(*) FROM country_metadata WHERE area_km2 > (SELECT AVG(area_km2) FROM country_metadata)) AS num_countries_large_area,
    (SELECT COUNT(*) FROM country_metadata WHERE area_km2 > (SELECT MAX(area_km2) FROM country_metadata)) AS num_countries_very_large_area;

SELECT official_name
FROM countries
WHERE LENGTH(calling_code) < (SELECT AVG(LENGTH(calling_code)) FROM countries);

